import { describe, it, mock } from "node:test";
import assert from "node:assert/strict";
import { runInSandbox } from "../dist/runner.js";

function makeMockBridge(tools = []) {
  return {
    getToolDefs: () => tools,
    callTool: mock.fn(async (_name, _args) => ({ ok: true })),
  };
}

describe("runInSandbox", () => {
  it("returns a string from simple code", async () => {
    const bridge = makeMockBridge();
    const result = await runInSandbox('return "hello"', bridge);
    assert.equal(result, "hello");
  });

  it("returns empty string when code returns undefined", async () => {
    const bridge = makeMockBridge();
    const result = await runInSandbox("return undefined", bridge);
    assert.equal(result, "");
  });

  it("returns empty string when code returns null", async () => {
    const bridge = makeMockBridge();
    const result = await runInSandbox("return null", bridge);
    assert.equal(result, "");
  });

  it("coerces non-string returns to string", async () => {
    const bridge = makeMockBridge();
    const result = await runInSandbox("return 42", bridge);
    assert.equal(result, "42");
  });

  it("throws on syntax errors", async () => {
    const bridge = makeMockBridge();
    await assert.rejects(
      () => runInSandbox("return {{invalid}}", bridge),
      { message: /Sandbox syntax error/ }
    );
  });

  it("truncates output exceeding MAX_RETURN_LENGTH", async () => {
    const bridge = makeMockBridge();
    const result = await runInSandbox(
      'return "x".repeat(5000)',
      bridge
    );
    assert.ok(result.length < 5000, "result should be truncated");
    assert.ok(
      result.includes("[truncated, 5000 chars total]"),
      "should include truncation marker"
    );
    const contentPart = result.split("\n")[0];
    assert.equal(contentPart.length, 4000, "content before marker should be 4000 chars");
  });

  it("does not truncate output at exactly MAX_RETURN_LENGTH", async () => {
    const bridge = makeMockBridge();
    const result = await runInSandbox(
      'return "x".repeat(4000)',
      bridge
    );
    assert.equal(result.length, 4000);
    assert.ok(!result.includes("[truncated"), "should not be truncated");
  });

  it("wires tool functions with hyphen-to-underscore naming", async () => {
    const callTool = mock.fn(async () => "tool-result");
    const bridge = {
      getToolDefs: () => [
        { name: "my-server__my-tool", description: "test tool" },
      ],
      callTool,
    };
    const result = await runInSandbox(
      'const r = await tools.my_server__my_tool({ q: "test" }); return String(r)',
      bridge
    );
    assert.equal(result, "tool-result");
    assert.equal(callTool.mock.calls.length, 1);
    assert.equal(callTool.mock.calls[0].arguments[0], "my-server__my-tool");
  });

  it("denies access to process global", async () => {
    const bridge = makeMockBridge();
    await assert.rejects(
      () => runInSandbox("return process.env.HOME", bridge),
      /process is not defined/
    );
  });

  it("denies access to require", async () => {
    const bridge = makeMockBridge();
    await assert.rejects(
      () => runInSandbox('return require("fs")', bridge),
      /require is not defined/
    );
  });

  it("supports await in code", async () => {
    const bridge = makeMockBridge();
    const result = await runInSandbox(
      "const x = await Promise.resolve(99); return String(x)",
      bridge
    );
    assert.equal(result, "99");
  });
});
